#include "controller.h"

#include <stdbool.h>
#include <string.h>

static void controller_set_safe_vent(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_vent(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

static bool is_sensor_stale(const controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return true;
    }

    /* Check pressure staleness */
    if (controller->has_valid_pressure) {
        const uint32_t age_ms = now_ms - controller->last_pressure_ms;
        if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    } else {
        /* No valid pressure reading ever */
        return true;
    }

    /* Check door staleness */
    if (controller->has_valid_door) {
        const uint32_t age_ms = now_ms - controller->last_door_ms;
        if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    } else {
        /* No valid door reading ever */
        return true;
    }

    return false;
}

static void apply_control_policy(controller_t *controller, bool door_closed, int pressure_kpa)
{
    if (controller == NULL) {
        return;
    }

    /* If door is open, always vent */
    if (!door_closed) {
        controller_set_safe_vent(controller);
        return;
    }

    /* Door closed - apply pressure-based policy */
    if (pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
        /* Low pressure: pressurize */
        controller->compressor_on = true;
        controller->vent_open = false;
        controller->state = CONTROLLER_STATE_PRESSURIZING;
    } else if (pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
        /* High pressure: relieve */
        controller->compressor_on = false;
        controller->vent_open = true;
        controller->state = CONTROLLER_STATE_RELIEVING;
    } else {
        /* In band: hold previous state */
        controller->state = CONTROLLER_STATE_HOLDING;
        /* Preserve previous compressor and vent settings */
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;

    if (controller == NULL) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    /* Check for sensor staleness - this takes priority */
    bool is_pressure_stale = false;
    bool is_door_stale = false;

    if (input.kind == CONTROLLER_INPUT_PRESSURE) {
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        is_pressure_stale = false;
    } else if (input.kind == CONTROLLER_INPUT_DOOR_OPEN || input.kind == CONTROLLER_INPUT_DOOR_CLOSED) {
        controller->has_valid_door = true;
        controller->door_closed = (input.kind == CONTROLLER_INPUT_DOOR_CLOSED);
        controller->last_door_ms = input.now_ms;
        is_door_stale = false;
    } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
               input.kind == CONTROLLER_INPUT_INVALID_PRESSURE ||
               input.kind == CONTROLLER_INPUT_INVALID_DOOR) {
        /* Invalid/malformed input - reset validity */
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        controller_set_safe_vent(controller);
        output.timed_out = true;
        return output;
    } else if (input.kind == CONTROLLER_INPUT_NONE) {
        /* No input - check for staleness */
        if (!controller->has_valid_pressure || !controller->has_valid_door) {
            /* Either no readings ever or one sensor is missing */
            controller_set_safe_vent(controller);
            output.timed_out = true;
            return output;
        }

        /* Both sensors valid - check staleness */
        if (is_sensor_stale(controller, input.now_ms)) {
            controller_set_safe_vent(controller);
            output.timed_out = true;
            return output;
        }

        /* Sensors are fresh - apply policy based on current state */
        bool door_closed = controller->door_closed;
        int pressure_kpa = controller->last_pressure_kpa;
        apply_control_policy(controller, door_closed, pressure_kpa);
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);

    /* Check if we timed out */
    if (is_sensor_stale(controller, input.now_ms)) {
        output.timed_out = true;
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PRESSURIZING:
        return "STATE PRESSURIZING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_RELIEVING:
        return "STATE RELIEVING";
    case CONTROLLER_STATE_SAFE_VENT:
    default:
        return "STATE SAFE_VENT";
    }
}

