        return true;
    }

    /* Check door staleness */
    if (controller->has_valid_door) {
        const uint32_t age_ms = now_ms - controller->last_door_ms;
        if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    } else {
        /* No valid door reading ever */
        return true;
    }

    return false;
}

static void apply_control_policy(controller_t *controller, bool door_closed, int pressure_kpa)
{
    if (controller == NULL) {
        return;
    }

    /* If door is open, always vent */
    if (!door_closed) {
        controller_set_safe_vent(controller);
        return;
    }

    /* Door closed - apply pressure-based policy */
    if (pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
